export class NetworkError extends Error{constructor(r,s){super(r),this.name="NetworkError",this.status=s}}export class FileError extends Error{constructor(r){super(r),this.name="FileError"}}export class ServerError extends Error{constructor(r,s){super(r),this.name="ServerError",this.status=s}}export class InvalidInputError extends Error{constructor(r){super(r),this.name="InvalidInputError"}}